/**
 * Format date for backend (DD/MM/YYYY HH:mm or DD/MM/YYYY)
 */
const formatDate = (date, includeTime = false) => {
  if (!date) return null;
  const d = new Date(date);
  const day = String(d.getDate()).padStart(2, '0');
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const year = d.getFullYear();
  
  if (includeTime) {
    const hours = String(d.getHours()).padStart(2, '0');
    const minutes = String(d.getMinutes()).padStart(2, '0');
    return `${day}/${month}/${year} ${hours}:${minutes}`;
  }
  return `${day}/${month}/${year}`;
};

const INT_MAX = 2147483647;

const toSafeIntId = (value) => {
  const parsed = Number(value);
  if (!Number.isInteger(parsed) || parsed <= 0 || parsed > INT_MAX) {
    return 0;
  }
  return parsed;
};

/**
 * Build Sale Order Master payload
 */
export function buildSaleOrderPayload(formState, companyId, employeeRefId) {
  
  // Build SaleOrderDetails array from grid data
  const SaleOrderDetails = (formState.saleOrderDetails || []).map((item, index) => ({
    id: toSafeIntId(item.id),
    saleOrderMasterRefId: formState.id || 0,
    itemMasterRefId: item.productId || null,
    mrp: 0,
    purchaseRate: 0,
    itemQty: parseFloat(item.qty) || 0,
    discPer: 0,
    discAmount: 0,
    landingCost: 0,
    taxPercent: parseFloat(item.taxPercentage) || 0,
    taxAmount: parseFloat(item.gstAmount) || 0,
    salesRate: parseFloat(item.rate) || 0,
    netSalesRate: 0,
    amount: parseFloat(item.amount) || 0,
    currencyValue: formState.currencyValue || 0,
    actualAmount: parseFloat(item.amount) || 0,
    sdRemarks: item.remarks || "",
    taxRefId: item.taxRefId || null
  }));

  // Build pickupDetails array from formState.pickupDetails
  const pickupDetails = (formState.pickupDetails || []).map((pickup, index) => ({
    id: toSafeIntId(pickup.id),
    saleOrderMasterRefId: formState.id || 0,
    pickupAddress: pickup.address || pickup.pickupAddress || "",
    pickupTime: pickup.datetime ? formatDate(pickup.datetime, true) : (pickup.pickupTime ? formatDate(pickup.pickupTime, true) : null),
    pickupWeaight: pickup.weight || pickup.pickupWeaight || "",
    pickupQuantity: pickup.quantity || pickup.pickupQuantity || "",
    rowNumber: index + 1
  }));

  // Build deliveryDetails array from formState.deliveryDetails
  const deliveryDetails = (formState.deliveryDetails || []).map((delivery, index) => ({
    id: toSafeIntId(delivery.id),
    saleOrderMasterRefId: formState.id || 0,
    deliveryAddress: delivery.address || delivery.deliveryAddress || "",
    deliveryTime: delivery.datetime ? formatDate(delivery.datetime, true) : (delivery.deliveryTime ? formatDate(delivery.deliveryTime, true) : null),
    deliveryWeight: delivery.weight || delivery.deliveryWeight || "",
    deliveryQuantity: delivery.quantity || delivery.deliveryQuantity || "",
    rowNumber: index + 1
  }));

  // Build forwardingDetails array from formState.forwardingDetails
  const forwardingDetails = (formState.forwardingDetails || []).map((fwd, index) => ({
    id: toSafeIntId(fwd.id),
    saleOrderMasterRefId: formState.id || 0,
    forwardingDate: fwd.createdDate ? formatDate(fwd.createdDate, false) : null,
    forwardingName: fwd.fw || null,
    enterRef: fwd.rNo || "",
    smkNo: fwd.smkNo || "",
    sealByRefId: fwd.sealBy ? parseInt(fwd.sealBy) : null,
    sealAmount: fwd.sealAmount || 0.0,
    breakSealByRefId: fwd.bSealBy ? parseInt(fwd.bSealBy) : null,
    breakSealAmount: fwd.bSealAmount || 0.0,
    exitRef: fwd.releaseNc || "",
    quantity: fwd.fQ || "",
    s1: fwd.s1 ? parseInt(fwd.s1) : null,
    s2: fwd.s2 ? parseInt(fwd.s2) : null,
    rowNumber: index + 1
  }));

  // Build main object
  const payload = {
    id: toSafeIntId(formState.id),
    spotId: formState.spotId || null,
    companyRefId: companyId,
    userRefId: null,
    employeeRefId: employeeRefId == 0 ? null : employeeRefId,
    agentCompanyRefId: formState.agentCompanyRefId || null,
    agentMasterRefId: formState.agentId || null,
    oAgentCompanyRefId: formState.oAgentCompanyRefId || null,
    oAgentMasterRefId: formState.oAgentId || null,
    customerRefId: formState.customerId || null,
    jobMasterRefId: formState.jobTypeRefId || null,
    saleDate: formatDate(formState.jobDate, false),
    saleType: formState.saleType || "",
    cNumberDisplay: "0",
    cNumber: 0,
    coinage: formState.coinage || 0.0,
    sportSaleOrderId: formState.spotSaleOrderId || null,
    grossAmount: formState.totalAmount || 0.0,
    taxAmount: formState.taxAmount || 0.0,
    discountAmount: 0,
    remarks: formState.remarks || "",
    remarks1: formState.remarks1 || "",
    plusAmount: 0,
    minusAmount: 0,
    doDescription: formState.doDescription || "",
    amount: formState.totalAmount || 0,
    offVesselName: formState.offVesselName || "",
    loadingVesselName: formState.loadingVesselName || "",
    billType: formState.billType || "",
    sPort: formState.sPort || null,
    oPort: formState.oPort || null,
    vessel: formState.loadingVesselType || null,
    oVessel: formState.offVesselType || null,
    commodity: formState.commodity || null,
    cargo: formState.cargo || null,
    eta: formState.loadingEta ? formatDate(formState.loadingEta, true) : null,
    etb: formState.loadingEtb ? formatDate(formState.loadingEtb, true) : null,
    etd: formState.loadingEtd ? formatDate(formState.loadingEtd, true) : null,
    oEta: formState.offEta ? formatDate(formState.offEta, true) : null,
    oEtb: formState.offEtb ? formatDate(formState.offEtb, true) : null,
    oEtd: formState.offEtd ? formatDate(formState.offEtd, true) : null,
    docNo: null,
    invoiceNo: null,
    truckRefId: formState.vehicleId || null,
    driverRefId: formState.driverId || null,
    awbNo: formState.awbNo || "",
    ptw: formState.ptwNo || "",
    lptw: formState.lPtwNo || "",
    optw: formState.oPtwNo || "",
    blCopy: formState.blCopy || "",
    quantity: formState.quantity || "",
    totalWeight: formState.weight || "",
    truckSize: formState.truckSize || "",
    jStatus: formState.statusRefId || null,
    oStatus: 0,
    boardingOfficerRefId: formState.officer1 || null,
    boardingOfficer1RefId: formState.officer2 || null,
    boardingAmount: formState.amt1 || null,
    boardingAmount1: formState.amt2 || null,
    origin: formState.origin || "",
    destination: formState.destination || "",
    currencyValue: formState.currencyValue || 0,
    actualNetAmount: formState.actualNetAmount || 0,
    flightTime: formState.loadingFlightTime ? formatDate(formState.loadingFlightTime, true) : null,
    SaleOrderDetails: SaleOrderDetails,
    pickupDetails: pickupDetails,
    deliveryDetails: deliveryDetails,
    forwardingDetails: forwardingDetails
  };

  return payload;
}

/**
 * Entry point called from useSaleOrder.js handleSave
 * Accepts the combined save params object and delegates to buildSaleOrderPayload
 */
export function handleSaveSaleOrder({
  formData,
  tableData = [],
  pickupAddresses = [],
  deliveryAddresses = [],
  commonOrigin = '',
  commonDestination = '',
  warehouseAddress = '',
  warehouseEnterDate = '',
  warehouseExitDate = '',
  forwardingRows = [],
  companyId,
  employeeRefId
}) {
  // Merge everything into a single formState object that buildSaleOrderPayload understands
  const formState = {
    ...formData,
    // Map address manager arrays to the expected keys
    saleOrderDetails: tableData,
    pickupDetails: pickupAddresses,
    deliveryDetails: deliveryAddresses,
    forwardingDetails: forwardingRows,
    // Map common origin/destination
    origin: commonOrigin,
    destination: commonDestination,
    // Warehouse
    warehouseAddress: warehouseAddress,
    warehouseEnterDate: warehouseEnterDate,
    warehouseExitDate: warehouseExitDate,
  };

  return buildSaleOrderPayload(formState, companyId, employeeRefId);
}
