import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast, { Toaster } from 'react-hot-toast';
import EmployeeForm from './EmployeeForm';
import { validateEmployee } from './employee.validation';
import { initialEmployeeState } from './Employee.initialState';


export default function EmployeePage() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState(initialEmployeeState);
  const [errors, setErrors] = useState({});

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;

    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));

    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: undefined }));
    }
  };

  const handleToggleActive = () => {
    setFormData(prev => ({ ...prev, active: !prev.active }));
  };

  const handleSave = () => {
    const validationErrors = validateEmployee(formData);

    if (Object.keys(validationErrors).length === 0) {
      setErrors({});
      toast.success('Employee saved successfully 🎉');

      const payload = {
        ...formData,
        active: formData.active ? 1 : 0
      };

      console.log(payload);
    } else {
      setErrors(validationErrors);
      toast.error('Please fix validation errors');
    }
  };

  return (
    <>
      <Toaster position="top-right" />
      <EmployeeForm
        formData={formData}
        errors={errors}
        onChange={handleChange}
        onToggleActive={handleToggleActive}
        onSave={handleSave}
        onUpdate={() => toast.success('Updated')}
        onDocuments={() => toast('Document management coming soon')}
        onCancel={() => navigate('/dashboard')}
      />
    </>
  );
}